export class Timer {
    duration;
    onUpdate;
    onFinish;
    #time;
    constructor(duration) {
        this.duration = duration;
        this.#time = 0;
    }
    get finished() {
        return this.#time > this.duration;
    }
    update(deltaTime, luaExecutor) {
        if (this.#time > this.duration) {
            return;
        }
        this.#time += deltaTime;
        luaExecutor(this.onUpdate);
        if (this.#time > this.duration) {
            luaExecutor(this.onFinish);
        }
    }
}
